// Handle both JSearch and RemoteOK field names
const jobId = $json.job_id || $json.id || $json.slug || 'Unknown';
const jobTitle = ($json.job_title || $json.position || '').replace(/"/g, "'");
const company = ($json.employer_name || $json.company || '').replace(/"/g, "'");
const datePosted = $json.job_posted_at_datetime_utc || $json.date || '';
const desc = ($json.job_description || $json.description || '')
  .substring(0, 1500)
  .replace(/[\n\r\t]/g, ' ')
  .replace(/"/g, "'");

return [{
  json: {
    clean_prompt: `Return ONLY a valid JSON object with these exact keys: job_id (copy exactly: "${jobId}"), job_title (copy exactly: "${jobTitle}"), company (copy exactly: "${company}"), date_posted (copy exactly: "${datePosted}"), skills (array of technical skills like SQL Python Excel Power BI Tableau etc), work_type (Remote or Hybrid or On-site or Unknown), province (Canadian province code ON BC AB QC etc or Remote or Unknown), seniority (Junior or Mid or Senior or Unknown). Extract skills/work_type/province/seniority from this description: ${desc}`
  }
}];

function shortId(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  const a = (h >>> 0).toString(36);
  const b = ((str.length * 2654435761) >>> 0).toString(36);
  return (a + b).padEnd(12, '0').slice(0, 12);
}

const PROV_MAP = {
  'ontario':'ON','on':'ON','quebec':'QC','québec':'QC','qc':'QC',
  'alberta':'AB','ab':'AB','british columbia':'BC','bc':'BC',
  'manitoba':'MB','mb':'MB','saskatchewan':'SK','sk':'SK',
  'nova scotia':'NS','ns':'NS','new brunswick':'NB','nb':'NB',
  'newfoundland and labrador':'NL','newfoundland':'NL','nl':'NL',
  'prince edward island':'PE','pei':'PE','pe':'PE',
  'yukon':'YT','yt':'YT','northwest territories':'NT','nt':'NT',
  'nunavut':'NU','nu':'NU',
};

function extractProvince(loc = '', country = '') {
  const s = String(loc).toLowerCase();
  const m = s.match(/,\s*([a-z]{2})\b/);
  if (m && PROV_MAP[m[1]]) return PROV_MAP[m[1]];
  for (const key of Object.keys(PROV_MAP)) {
    if (key.length > 2 && s.includes(key)) return PROV_MAP[key];
  }
  const c = String(country).toLowerCase();
  if (c && !c.includes('canada') && c !== 'ca') return 'Non-CA';
  return 'Unknown';
}

function inferSource(base) {
  if (base.source) return base.source;
  const url = (base.url || base.job_apply_link || base.redirect_url || '').toLowerCase();
  if (url.includes('remoteok')) return 'RemoteOK';
  return 'JSearch';
}

function safeParse(content) {
  if (!content) return null;
  if (typeof content !== 'string') return content;
  try { return JSON.parse(content); } catch (_) {}
  const lastBrace = content.lastIndexOf('}');
  if (lastBrace > 0) {
    try { return JSON.parse(content.slice(0, lastBrace + 1)); } catch (_) {}
    try { return JSON.parse(content.slice(0, lastBrace + 1) + ']}'); } catch (_) {}
  }
  return null;
}

const out = [];
const collectedAt = new Date().toISOString();

const groqItems = $input.all();
const batcherItems = $('Code in JavaScript3').all();

for (let i = 0; i < groqItems.length; i++) {
  const raw = groqItems[i].json;
  const batch = batcherItems[i]?.json || {};
  const originals = batch.originals || [];

  const content = raw?.choices?.[0]?.message?.content;
  const parsed = safeParse(content);
  if (!parsed) continue;

  const results = parsed.results || [];

  for (const r of results) {
    const orig = originals.find(o => o.id === r.id) || originals[r.id] || {};
    const base = orig._original || {};

    const job_title   = base.title || base.position || base.job_title || orig.title || '';
    const company     = base.company || base.company_name || base.employer_name || orig.company || '';
    const location    = base.location || base.candidate_required_location || base.job_city || orig.location || '';
    const country     = base.job_country || base.country || '';
    const url         = base.url || base.job_apply_link || base.redirect_url || '';
    const date_posted = base.date || base.job_posted_at_datetime_utc || base.posted_at || base.publication_date || '';

    const idSource = url || `${job_title}|${company}|${location}`;

    out.push({
      json: {
        job_id: shortId(idSource),
        job_title,
        company,
        province: extractProvince(location, country),
        work_type: r.work_type || 'Unknown',
        seniority: r.seniority || 'Unknown',
        skills: Array.isArray(r.skills) ? r.skills.join(', ') : (r.skills || ''),
        date_posted,
        source: inferSource(base),
        collected_at: collectedAt,
      },
    });
  }
}

return out;

const jobId = $json.job_id || $json.id || $json.slug || 'Unknown';
const jobTitle = ($json.job_title || $json.position || '').replace(/"/g, '').replace(/'/g, '');
const company = ($json.employer_name || $json.company || '').replace(/"/g, '').replace(/'/g, '');
const datePosted = $json.job_posted_at_datetime_utc || $json.date || '';
const desc = ($json.job_description || $json.description || '')
  .substring(0, 1500)
  .replace(/[\n\r\t"]/g, ' ');

const prompt = 'Return ONLY a valid JSON object with these exact keys: ' +
  'job_id (value: ' + jobId + '), ' +
  'job_title (value: ' + jobTitle + '), ' +
  'company (value: ' + company + '), ' +
  'date_posted (value: ' + datePosted + '), ' +
  'skills (array of technical skills like SQL Python Excel Power BI Tableau etc), ' +
  'work_type (Remote or Hybrid or On-site or Unknown), ' +
  'province (Canadian province code ON BC AB QC etc or Remote or Unknown), ' +
  'seniority (Junior or Mid or Senior or Unknown). ' +
  'Extract skills/work_type/province/seniority from this description: ' + desc;

return {
  json: {
    clean_prompt: prompt
  }
};
function seniorityFromTitle(t = '') {
  const s = t.toLowerCase();
  if (/\bintern\b/.test(s)) return 'Intern';
  if (/\b(junior|jr\.?|associate|entry|graduate|early career)\b/.test(s)) return 'Junior';
  if (/\b(senior|sr\.?|lead|principal|staff)\b/.test(s)) return 'Senior';
  return null;
}
function workTypeFromText(text = '') {
  const s = text.toLowerCase();
  if (/\bremote\b|\bwork from home\b|\bwfh\b/.test(s)) return 'Remote';
  if (/\bhybrid\b/.test(s)) return 'Hybrid';
  if (/\bon[-\s]?site\b|\bin[-\s]?office\b/.test(s)) return 'Onsite';
  return null;
}
// Apply to each item before returning
