const CHUNK_SIZE = 5;

const SYSTEM_PROMPT = `You analyze job postings and return structured data.

INPUT: a JSON object with key "jobs" = array of postings (each has id, title, company, location, description).

OUTPUT: a JSON object with key "results" = an array with one entry per input job, IN THE SAME ORDER.

Each result entry MUST have:
- id: number, copied from the input
- seniority: one of "Intern","Junior","Mid","Senior","Lead","Unknown"
- work_type: one of "Remote","Hybrid","Onsite","Unknown"
- skills: array of strings (e.g. ["SQL","Python","Power BI"])

EXAMPLE:
Input: {"jobs":[{"id":0,"title":"Senior Data Analyst","company":"Acme","location":"Toronto, ON","description":"SQL Python Tableau required. Hybrid role."}]}
Output: {"results":[{"id":0,"seniority":"Senior","work_type":"Hybrid","skills":["SQL","Python","Tableau"]}]}

Rules:
- Always return ALL input jobs in results, never an empty array unless the input jobs array is empty.
- Output valid JSON only. No prose, no markdown.`;

const items = $input.all().map(i => i.json);

const slim = items.map((j, idx) => ({
  id: idx,
  title: j.title || j.position || j.job_title || '',
  company: j.company || j.company_name || j.employer_name || '',
  location: j.location || j.candidate_required_location || j.job_city || '',
  description: (j.description || j.job_description || '').slice(0, 800),
  _original: j,
}));

const batches = [];
for (let i = 0; i < slim.length; i += CHUNK_SIZE) {
  const chunk = slim.slice(i, i + CHUNK_SIZE);
  const jobs_for_llm = chunk.map(({ _original, ...rest }) => rest);

  batches.push({
    json: {
      groq_body: {
        model: "llama-3.3-70b-versatile",   // ← back from 8b-instant,
        temperature: 0,
        max_tokens: 2000,
        response_format: { type: "json_object" },
        messages: [
          { role: "system", content: SYSTEM_PROMPT },
          {
            role: "user",
            content: `Analyze these ${jobs_for_llm.length} job postings and return results for ALL of them:\n\n${JSON.stringify({ jobs: jobs_for_llm })}`,
          },
        ],
      },
      originals: chunk,
    },
  });
}

return batches;
